simple_types.code:
type Color_Component is range 0 .. 255 with
  Size       => 8,
  Convention => C;

array_types.code:
type RGB32_Display_Buffer is array
  (Display_Vertical_Range, Display_Horizontal_Range) of RGB32_Color with
  Convention => C;

record_types.code:
type RGB32_Color is
   record
      Red   : Color_Component;
      Green : Color_Component;
      Blue  : Color_Component;
   end record;
